class Solution {
    public int calculate(String s) {
        int result = 0;
        int sign = 1;
        int num = 0;
        int i = 0;
        while (i < s.length()) {
            if (Character.isDigit(s.charAt(i))) {
                num = num * 10 + (s.charAt(i) - '0');
            } else if (s.charAt(i) == ' ') {
                i++;
                continue;
            } else if (s.charAt(i) == '+' || s.charAt(i) == '-' || s.charAt(i) == '*' || s.charAt(i) == '/') {
                result += sign * num;
                sign = (s.charAt(i) == '+' || s.charAt(i) == '*') ? 1 : -1;
                num = 0;
                i++;
            }
        }
        result += sign * num;
        return result;
    }
}
```

